// ========== 重设密码验证函数 ==========
static int reset_password(const char *phone, const char *new_password, 
                          const char *confirm_password, const char *code,
                          char *err_msg, int err_size)
{
    // 1. 验证电话号码
    if(!phone || strlen(phone) == 0) {
        snprintf(err_msg, err_size, "请输入电话号码");
        return -1;
    }
    if(!is_valid_phone(phone)) {
        snprintf(err_msg, err_size, "请输入11位数字电话号码");
        return -2;
    }
    
    // 2. 检查账号是否存在
    int idx = find_user_by_phone(phone);
    if(idx < 0) {
        snprintf(err_msg, err_size, "该账号不存在，请先注册");
        return -3;
    }
    
    // 3. 获取用户信息
    const AuthUser *user = get_user_by_index(idx);
    if(!user) {
        snprintf(err_msg, err_size, "系统错误");
        return -4;
    }
    
    // 4. 验证验证码
    if(!code || strlen(code) == 0) {
        snprintf(err_msg, err_size, "请输入验证码");
        return -5;
    }
    if(!verify_code(code)) {
        snprintf(err_msg, err_size, "验证码错误");
        return -6;
    }
    
    // 5. 验证新密码
    if(strlen(new_password) == 0) {
        snprintf(err_msg, err_size, "请输入新密码");
        return -7;
    }
    if(strlen(new_password) < 6) {
        snprintf(err_msg, err_size, "密码长度不能少于6位");
        return -8;
    }
    
    // 6. 检查新密码是否与原始密码相同
    if(strcmp(new_password, user->password) == 0) {
        snprintf(err_msg, err_size, "新密码不能与原始密码相同");
        return -9;
    }
    
    // 7. 验证确认密码
    if(strlen(confirm_password) == 0) {
        snprintf(err_msg, err_size, "请再次输入新密码");
        return -10;
    }
    if(strcmp(new_password, confirm_password) != 0) {
        snprintf(err_msg, err_size, "两次输入的密码不一致");
        return -11;
    }
    
    // 8. 更新密码
    int result = update_user_password(idx, new_password);
    if(result != 0) {
        snprintf(err_msg, err_size, "密码更新失败");
        return -12;
    }
    
    snprintf(err_msg, err_size, "密码重设成功！");
    return 0;
}

