// 重设密码按钮事件
void ui_event_Button4(lv_event_t * e)
{
    if(lv_event_get_code(e) == LV_EVENT_CLICKED) {
        if(keyboard_visible) {
            show_warning_message("请先关闭键盘", 1500);
            return;
        }
        
        const char *phone = lv_textarea_get_text(ui_TextArea8);
        const char *new_password = lv_textarea_get_text(ui_TextArea9);
        const char *confirm_password = lv_textarea_get_text(ui_TextArea10);
        const char *code = lv_textarea_get_text(ui_TextArea_code);
        
        char err_msg[128];
        int result = reset_password(phone, new_password, confirm_password, code, err_msg, sizeof(err_msg));
        
        if(result == 0) {
            // 重设成功 - 显示成功弹窗
            show_success_message(err_msg, 1500);
            
            // 清空输入框
            lv_textarea_set_text(ui_TextArea8, "");
            lv_textarea_set_text(ui_TextArea9, "");
            lv_textarea_set_text(ui_TextArea10, "");
            lv_textarea_set_text(ui_TextArea_code, "");
            
            // 延迟返回登录界面
            lv_timer_t * timer = lv_timer_create(delayed_return_to_screen2, 1500, NULL);
            lv_timer_set_repeat_count(timer, 1);
        } else {
            // 重设失败 - 显示错误弹窗
            show_error_message(err_msg, 2000);
        }
        
        // 无论成功还是失败，都刷新验证码
        generate_code();
    }
}

